// Acepta dos formatos en la URL:
//   ?from=YYYY-MM-DD&to=YYYY-MM-DD     (rango libre)
//   ?week=YYYY-WW                      (semana ISO; lunes a domingo)
//
// Si no llega nada, default = última semana completa (lunes->domingo
// que ya terminó). Devuelve { from, to, label } para usar más abajo.
const raw = $input.first().json || {};
const q = raw.query || raw.params || {};

function parseISO(s) { const d = new Date(s + 'T00:00:00Z'); return isNaN(d.getTime()) ? null : d; }
function iso(d) { return d.toISOString().slice(0, 10); }

function lunesDeSemana(d) {
  // d es Date UTC. ISO weeks empiezan en lunes.
  const x = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
  const dow = x.getUTCDay() || 7; // 1..7
  if (dow !== 1) x.setUTCDate(x.getUTCDate() - (dow - 1));
  return x;
}

function semanaISO(d) {
  // Devuelve [year, week] ISO.
  const x = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
  const dow = x.getUTCDay() || 7;
  x.setUTCDate(x.getUTCDate() + 4 - dow);
  const yearStart = new Date(Date.UTC(x.getUTCFullYear(), 0, 1));
  const week = Math.ceil((((x - yearStart) / 86400000) + 1) / 7);
  return [x.getUTCFullYear(), week];
}

let from = null, to = null, label = '';

if (q.week && /^\d{4}-W?\d{1,2}$/i.test(q.week)) {
  // ISO YYYY-WW
  const [y, w] = String(q.week).replace('W', '').split('-').map(Number);
  // Cálculo del lunes de la semana w del año y
  const enero4 = new Date(Date.UTC(y, 0, 4));
  const lunesW1 = lunesDeSemana(enero4);
  const lunes = new Date(lunesW1.getTime() + (w - 1) * 7 * 86400000);
  const domingo = new Date(lunes.getTime() + 6 * 86400000);
  from = iso(lunes); to = iso(domingo);
  label = `Semana ${w} de ${y}`;
} else if (q.from && q.to) {
  const dF = parseISO(q.from), dT = parseISO(q.to);
  if (!dF || !dT) throw new Error('from/to deben ser YYYY-MM-DD');
  from = iso(dF); to = iso(dT);
  label = `${from} → ${to}`;
} else {
  // Default: última semana ISO completa (la anterior a la actual)
  const ahora = new Date();
  const lunesActual = lunesDeSemana(ahora);
  const lunesPasada = new Date(lunesActual.getTime() - 7 * 86400000);
  const domingoPasada = new Date(lunesPasada.getTime() + 6 * 86400000);
  from = iso(lunesPasada); to = iso(domingoPasada);
  const [y, w] = semanaISO(lunesPasada);
  label = `Semana ${w} de ${y}`;
}

// Construye la query Zendesk Search:
//   created>=YYYY-MM-DD created<=YYYY-MM-DD type:ticket
const zendeskQuery = `type:ticket created>=${from} created<=${to}`;

return [{ json: { from, to, label, zendeskQuery } }];

// Recibe N tickets de Zendesk + el resultado de "Validar rango".
// Saca tipo / entorno / módulo de los custom fields, agrupa para los
// breakdowns de cabecera, y construye el prompt para GPT.

// IDs reales en yurest.zendesk.com — mismo set que el workflow 25.
const CUSTOM_FIELD_IDS = {
  tipo:    26672700540829,  // "Tipo de ticket"
  entorno: 27376906089629,  // "Entorno"
  modulo:  27243772817053   // "Módulo"
};

function extraerCustomField(t, id) {
  if (id == null) return null;
  const fuentes = [t.custom_fields, t.fields].filter(Array.isArray);
  for (const arr of fuentes) {
    const cf = arr.find(c => c && (c.id === id || String(c.id) === String(id)));
    if (cf && cf.value != null && cf.value !== '') return cf.value;
  }
  return null;
}

const rango = $('Validar rango').first().json;
const tickets = ($input.all() || []).map(it => it.json).filter(Boolean);

// Normaliza cada ticket con los campos que vamos a usar.
const norm = tickets.map(t => ({
  id:      t.id,
  subject: t.subject || t.title || t.descripcion || '(sin título)',
  status:  t.status || null,
  created_at: t.created_at || t.createdAt || null,
  tipo:    extraerCustomField(t, CUSTOM_FIELD_IDS.tipo)    || 'Sin tipo',
  entorno: extraerCustomField(t, CUSTOM_FIELD_IDS.entorno) || 'Sin entorno',
  modulo:  extraerCustomField(t, CUSTOM_FIELD_IDS.modulo)  || 'Sin módulo'
}));

// Breakdowns: cuenta por categoría y top-N.
function cuenta(arr, key) {
  const map = new Map();
  for (const x of arr) {
    const k = x[key];
    map.set(k, (map.get(k) || 0) + 1);
  }
  return [...map.entries()]
    .map(([nombre, count]) => ({ nombre, count }))
    .sort((a, b) => b.count - a.count);
}
const porTipo    = cuenta(norm, 'tipo');
const porEntorno = cuenta(norm, 'entorno');
const porModulo  = cuenta(norm, 'modulo');

// Prompt para GPT — el cuerpo principal del informe va escrito por la
// IA, los breakdowns numéricos los devuelve el workflow tal cual.
function listaTickets() {
  return norm.map((t, i) => `${i + 1}. [#${t.id}] [${t.tipo} · ${t.entorno} · ${t.modulo}] ${t.subject}`).join('\n');
}
function listaBreakdown(arr) {
  return arr.slice(0, 8).map(b => `  - ${b.nombre}: ${b.count}`).join('\n');
}

const superPrompt = `Eres un Senior Support Manager en Yurest, una plataforma SaaS de\
gestión integral para hostelería. Te pasamos los tickets recibidos\
esta semana con su Tipo, Entorno (Producción/Staging/etc), Módulo\
afectado y asunto. Tu trabajo es generar un informe ejecutivo breve\
que ayude al equipo de Producto y Soporte a saber dónde poner foco.\n\n\
## DATOS DEL PERIODO\n\
- **Periodo**: ${rango.label} (${rango.from} → ${rango.to})\n\
- **Tickets totales**: ${norm.length}\n\
- **Por tipo**:\n${listaBreakdown(porTipo)}\n\
- **Por entorno**:\n${listaBreakdown(porEntorno)}\n\
- **Por módulo**:\n${listaBreakdown(porModulo)}\n\n\
## LISTADO\n\
${listaTickets()}\n\n\
## ESTRUCTURA DEL INFORME\n\
Responde **en español** y en formato Markdown, siguiendo este esquema\
exacto:\n\n\
### 🩺 Diagnóstico de la semana\n\
Un párrafo (3-5 líneas) con la lectura general — volumen vs semana\
típica, qué destaca, salud global del producto.\n\n\
### 🔥 Temas calientes\n\
Lista de 3-5 patrones recurrentes detectados en los asuntos. Cada uno:\
**Negrita el tema**, una línea explicando, y entre paréntesis cuántos\
tickets aproximados lo tocan. Ejemplos: "crashes al cerrar caja",\
"errores de sincronización con TPV X", "confusión con la nueva\
función Y".\n\n\
### 🎯 Recomendaciones\n\
2-3 acciones concretas:\n\
- 🛠️ **Soporte**: qué responder/preparar para clientes recurrentes.\n\
- 💻 **Producto**: qué bug arreglar o qué feature/UX revisar.\n\
- 📚 **Documentación**: qué FAQ o guía actualizar.\n\n\
### 📊 Lectura rápida\n\
- **Entorno con más tickets**: <nombre + count>.\n\
- **Módulo con más tickets**: <nombre + count>.\n\
- **Tipo dominante**: <nombre + count>.\n\n\
### Tono\n\
Claro, ejecutivo, sin paja. Si hay menos de 5 tickets en total, di que\
es una semana tranquila y resume en 2-3 frases. Usa los emojis sólo\
en los headings.`;

// Devolvemos un único item con todo lo que el resto del flujo necesita.
return [{
  json: {
    prompt_final: superPrompt,
    rango,
    total: norm.length,
    porTipo,
    porEntorno,
    porModulo,
    tickets: norm
  }
}];

// Combina la respuesta de GPT con los datos estructurados que ya
// teníamos del nodo "Preparar prompt". El front recibe el resumen
// como markdown bruto + los breakdowns + la lista de tickets para
// poder pintar todo sin recalcular.

const prep = $('Preparar prompt').first().json;
const aiResp = $input.first().json || {};

// Antes hacíamos `String(aiResp.content)` directo, pero el nodo
// @n8n/n8n-nodes-langchain.openAi a veces devuelve `content` como
// OBJETO (p. ej. { text: '...' } o un array de partes) en lugar de
// string — y String(obj) imprime '[object Object]' que es lo que el
// usuario veía en la página. Este extractor recursivo desempaca
// arrays/objetos hasta llegar al texto real.
function extractText(c) {
  if (c == null) return '';
  if (typeof c === 'string') return c;
  if (Array.isArray(c)) {
    return c.map(extractText).filter(Boolean).join('');
  }
  if (typeof c === 'object') {
    if (typeof c.text === 'string')    return c.text;
    if (typeof c.content === 'string') return c.content;
    if (typeof c.output === 'string')  return c.output;
    if (typeof c.value === 'string')   return c.value;
    // Objeto con sub-claves no-string: probamos recursivo
    if (c.text)    return extractText(c.text);
    if (c.content) return extractText(c.content);
    if (c.output)  return extractText(c.output);
  }
  return '';
}

let resumenMd = '';
if (typeof aiResp === 'string') {
  resumenMd = aiResp;
} else if (Array.isArray(aiResp.choices) && aiResp.choices[0]?.message?.content) {
  resumenMd = extractText(aiResp.choices[0].message.content);
} else if (aiResp.message && aiResp.message.content) {
  resumenMd = extractText(aiResp.message.content);
} else if (aiResp.content) {
  resumenMd = extractText(aiResp.content);
} else if (aiResp.text) {
  resumenMd = extractText(aiResp.text);
} else if (aiResp.output) {
  resumenMd = extractText(aiResp.output);
}

// Si tras toda la cadena de fallbacks seguimos sin string usable,
// serializamos el payload entero para que el dev vea qué llegó.
if (!resumenMd || typeof resumenMd !== 'string') {
  try {
    resumenMd = '⚠️ Respuesta inesperada de OpenAI:\n```json\n' +
      JSON.stringify(aiResp, null, 2).slice(0, 800) + '\n```';
  } catch (_) { resumenMd = '(sin resumen)'; }
}

// GPT a veces devuelve el contenido envuelto en ```markdown … ```.
// Lo limpiamos para que el front no pinte la valla del fence.
resumenMd = resumenMd
  .replace(/^```(?:markdown|md)?\s*\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

return [{
  json: {
    success: true,
    rango:   prep.rango,
    total:   prep.total,
    porTipo: prep.porTipo,
    porEntorno: prep.porEntorno,
    porModulo: prep.porModulo,
    tickets: prep.tickets,
    resumen_markdown: resumenMd
  }
}];
